import{_ as e,o as a,c as o,a4 as i}from"./chunks/framework.wrug7QjT.js";const u=JSON.parse('{"title":"Japan — Country Brief","description":"Trans relocation guide for Japan: legal overview, visa options, cost of living, and key considerations.","frontmatter":{"layout":"doc","title":"Japan — Country Brief","description":"Trans relocation guide for Japan: legal overview, visa options, cost of living, and key considerations."},"headers":[],"relativePath":"countries/japan/index.md","filePath":"countries/japan/index.md","lastUpdated":1781006640000}'),r={name:"countries/japan/index.md"};function n(s,t,l,d,c,g){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="🇯🇵-japan" tabindex="-1"><span style="color:#bc002d;">🇯🇵 Japan</span> <a class="header-anchor" href="#🇯🇵-japan" aria-label="Permalink to &quot;&lt;span style=&quot;color: #bc002d;&quot;&gt;🇯🇵 Japan&lt;/span&gt;&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Field</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Capital</strong></td><td>Tokyo</td></tr><tr><td><strong>Language</strong></td><td>Japanese (limited English)</td></tr><tr><td><strong>Currency</strong></td><td>Japanese Yen (JPY)</td></tr><tr><td><strong>Equaldex Score</strong></td><td>33</td></tr><tr><td><strong>Trans-Specific Rating</strong></td><td>2/5</td></tr><tr><td><strong>Last Verified</strong></td><td>June 8, 2026</td></tr></tbody></table><h2 id="legal-overview" tabindex="-1">Legal Overview <a class="header-anchor" href="#legal-overview" aria-label="Permalink to &quot;Legal Overview&quot;">​</a></h2><ul><li><strong>Gender Recognition:</strong> Medicalised. The 2003 Gender Identity Disorder Law requires surgery and sterilisation for legal gender change. The 2023 Supreme Court ruling found the sterilisation requirement unconstitutional, but the law has not yet been updated.</li><li><strong>Anti-Discrimination Law:</strong> No federal law. Some municipal ordinances provide protections.</li><li><strong>Hate Crime Laws:</strong> None specific.</li><li><strong>Same-Sex Marriage:</strong> Not legal. Some municipalities offer partnership certificates.</li></ul><h2 id="healthcare" tabindex="-1">Healthcare <a class="header-anchor" href="#healthcare" aria-label="Permalink to &quot;Healthcare&quot;">​</a></h2><ul><li><strong>HRT Access:</strong> Gatekeeping. Requires a diagnosis of &quot;Gender Identity Disorder&quot; from a specialist. Some clinics in Tokyo use informed consent.</li><li><strong>Cost:</strong> JPY 10,000–20,000/month (≈ €65–130).</li></ul><h2 id="visa-pathways" tabindex="-1">Visa Pathways <a class="header-anchor" href="#visa-pathways" aria-label="Permalink to &quot;Visa Pathways&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Income Req.</th><th>Processing</th><th>Leads to PR?</th></tr></thead><tbody><tr><td>Digital Nomad Visa (2024)</td><td>JPY 10 million/year (≈ €65,000)</td><td>1–2 months</td><td>No</td></tr><tr><td>Work Visa</td><td>Job offer</td><td>1–4 months</td><td>Yes (10 years)</td></tr><tr><td>Student Visa</td><td>Proof of funds</td><td>1–3 months</td><td>Possible</td></tr></tbody></table><h2 id="cost-of-living-tokyo" tabindex="-1">Cost of Living (Tokyo) <a class="header-anchor" href="#cost-of-living-tokyo" aria-label="Permalink to &quot;Cost of Living (Tokyo)&quot;">​</a></h2><p>1-bedroom: JPY 80,000–150,000/month (≈ €520–980). Monthly budget: JPY 200,000–400,000 (≈ €1,300–2,600).</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li><strong>⚠️ Surgery requirement</strong> still effectively in place despite the 2023 ruling</li><li><strong>No federal protections</strong> — discrimination is legal in most contexts</li><li><strong>Social conservatism</strong> is high. Out trans people face significant barriers</li><li><strong>Japanese language essential</strong> for all aspects of life</li><li><strong>Safety</strong> is excellent — Japan has very low crime rates</li><li><strong>Asylum:</strong> Not available for LGBTQ+ claims</li></ul><p><em>Sources: ILGA, Equaldex, Japan Transgender Association. Last verified: June 8, 2026.</em></p>',13)])])}const p=e(r,[["render",n]]);export{u as __pageData,p as default};
